import { useState } from "react";
import { TreeCanvas } from "../../components/tree/TreeCanvas";
import type { TreeNode } from "../../components/tree/types";
import { GraphToolbar, useGraphFilter, defaultGraphFilter } from "../../components/graph";
import { initialTree } from "./data";
import { treeConfig } from "./config";
import { useRendererReusableTreeHandlers } from "./handlers";

/**
 * RendererReusableTree — a fully-typed, self-contained tree with a search / sort /
 * filter toolbar above the canvas.
 *
 * Drop into any page:
 *   <RendererReusableTree />
 *
 * To plug into a backend, edit the handlers in `./handlers.ts`. To remove the
 * toolbar, delete the `GraphToolbar`/`useGraphFilter` wiring below and set
 * `showToolbar: false` in `./config.ts`.
 */
export function RendererReusableTree() {
  const [tree, setTree] = useState<TreeNode>(initialTree);
  const [filter, setFilter] = useState(defaultGraphFilter);
  const { handleNodeAdd, handleNodeUpdate, handleNodeRemove, handleNodeMove } = useRendererReusableTreeHandlers();
  const { tree: filteredTree, matches, stats, allTags } = useGraphFilter(tree, filter);

  return (
    <div className="flex flex-col gap-2">
      <GraphToolbar
        filter={filter}
        onChange={setFilter}
        allTags={allTags}
        matched={stats.matched}
        total={stats.total}
      />
      <TreeCanvas
        config={treeConfig}
        tree={filter.mode === "hide" ? filteredTree : tree}
        onTreeChange={setTree}
        highlightIds={filter.mode === "dim" ? matches : undefined}
        onNodeAdd={handleNodeAdd}
        onNodeUpdate={handleNodeUpdate}
        onNodeRemove={handleNodeRemove}
        onNodeMove={handleNodeMove}
      />
    </div>
  );
}

import type { NodeRenderer } from "../../components/tree/types";
import { Badge } from "@/components/ui/badge";

/**
 * Case 1 — single reusable renderer.
 * Every node uses this body unless it defines its own `meta.render`.
 */
export const renderNode: NodeRenderer = ({ node, isRoot, childCount }) => (
  <div className="min-w-[160px] rounded-lg border-2 border-primary/40 bg-card px-3 py-2 shadow-sm">
    <div className="flex items-center justify-between gap-2">
      <span className="truncate text-sm font-semibold">{node.label}</span>
      {isRoot && <Badge className="h-4 px-1 text-[9px]">START</Badge>}
    </div>
    {node.meta?.description && (
      <div className="mt-1 truncate text-[10px] text-muted-foreground">{node.meta.description}</div>
    )}
    {childCount > 0 && (
      <div className="mt-1 text-[10px] text-primary">→ {childCount} branch{childCount === 1 ? "" : "es"}</div>
    )}
  </div>
);

import type { TreeNode } from "../../components/tree/types";

/** Initial tree data. Swap with your own backend fetch when wiring up production. */
export const initialTree: TreeNode = {
  "id": "trigger",
  "label": "Webhook received",
  "meta": {
    "description": "POST /events"
  },
  "children": [
    {
      "id": "validate",
      "label": "Validate payload",
      "meta": {
        "description": "Zod schema"
      },
      "children": [
        {
          "id": "enrich",
          "label": "Enrich with user",
          "meta": {
            "description": "users.find"
          },
          "children": [
            {
              "id": "notify",
              "label": "Notify Slack",
              "meta": {
                "description": "#alerts"
              }
            },
            {
              "id": "store",
              "label": "Persist event",
              "meta": {
                "description": "events table"
              }
            }
          ]
        },
        {
          "id": "dlq",
          "label": "Dead-letter",
          "meta": {
            "description": "DLQ topic"
          }
        }
      ]
    }
  ]
};

import { useCallback } from "react";
import type {
  TreeNodeAddEvent,
  TreeNodeUpdateEvent,
  TreeNodeRemoveEvent,
  TreeNodeMoveEvent,
} from "../../components/tree/types";

/**
 * One handler per mutation — wire each to your backend.
 */
export function useRendererReusableTreeHandlers() {
  const handleNodeAdd = useCallback((event: TreeNodeAddEvent) => {
    console.log("[tree] node added", event);
  }, []);

  const handleNodeUpdate = useCallback((event: TreeNodeUpdateEvent) => {
    console.log("[tree] node updated", event);
  }, []);

  const handleNodeRemove = useCallback((event: TreeNodeRemoveEvent) => {
    console.log("[tree] node removed", event);
  }, []);

  const handleNodeMove = useCallback((event: TreeNodeMoveEvent) => {
    console.log("[tree] node moved", event);
  }, []);

  return { handleNodeAdd, handleNodeUpdate, handleNodeRemove, handleNodeMove };
}
